$(document).ready(function() {
        var baseUrl = window.location.origin;
        let retrive_data = baseUrl+'/view_all_valaya';
        let edit_category = baseUrl+'/master/valaya/edit_valaya';
      
        // Initialize DataTable
        $('#view_valaya').DataTable({
            processing: true,
            serverSide: true,
            searching: true,
            scrollY: 500,
            scrollX: true,
            scrollCollapse: true,
            
            columnDefs: [{
                "defaultContent": "-",
                "targets": 0,
                "render": function (data, type, row, meta) {
                  // Return the serial number (row index + 1)
                  return meta.row + 1;
                }
              }],
            ajax: {
                url: retrive_data,
            },

            "columns": [
              { "data": null }, // This column will be used for serial numbers
                 
                { 
                  "data": "valaya_no",
                },
                { 
                  "data": "name",
                },
                
              { 
                title: 'Action',
                render: function(data, type, full) {
                  if(full.is_edit === 0)
                  {
                    return `
                    <a href='edit_valaya/${full.id}'><i class="ti-pencil-alt"></i></a>
                     `;   
                  }else{
                      return ''; 
                  } 
                }
            }

            ]
        });
});